const leads = $node["Consultar Leads en Airtable"].json.records || [];
const clientes = $node["Consultar Clientes en Airtable"].json.records || [];

function countByField(records, fieldName) {
  const result = {};
  for (const record of records) {
    const value = record.fields?.[fieldName] || "Sin valor";
    result[value] = (result[value] || 0) + 1;
  }
  return result;
}

const leadsByStatus = countByField(leads, "Estado");
const leadsByPriority = countByField(leads, "Prioridad");
const clientsByStatus = countByField(clientes, "Estado");

const totalLeads = leads.length;
const totalClientes = clientes.length;
const leadsNuevos = leadsByStatus["Nuevo"] || 0;
const leadsContactados = leadsByStatus["Contactado"] || 0;
const leadsSeguimiento = leadsByStatus["En seguimiento"] || 0;
const clientesExpedienteCreado = clientsByStatus["Expediente creado"] || 0;

const now = new Date();
const reportDate = now.toISOString().slice(0, 10);
const fileName = `follow-up-report-${reportDate}.txt`;

const reportText = `AUTOMATIC FOLLOW-UP REPORT\n\nReport date: ${reportDate}\n\nSUMMARY\n- Total leads: ${totalLeads}\n- New leads: ${leadsNuevos}\n- Contacted leads: ${leadsContactados}\n- Leads in follow-up: ${leadsSeguimiento}\n- Total clients: ${totalClientes}\n- Clients with created file: ${clientesExpedienteCreado}\n\nLEADS BY STATUS\n${Object.entries(leadsByStatus).map(([key, value]) => `- ${key}: ${value}`).join("\n") || "- No lead data available"}\n\nLEADS BY PRIORITY\n${Object.entries(leadsByPriority).map(([key, value]) => `- ${key}: ${value}`).join("\n") || "- No priority data available"}\n\nCLIENTS BY STATUS\n${Object.entries(clientsByStatus).map(([key, value]) => `- ${key}: ${value}`).join("\n") || "- No client data available"}\n\nBUSINESS NOTES\nReporte creado automaticamente desde n8n con informacion de Airtable\n`;

return [
  {
    json: {
      success: true,
      report_date: reportDate,
      report_file_name: fileName,
      total_leads: totalLeads,
      total_clients: totalClientes,
      leads_by_status: leadsByStatus,
      leads_by_priority: leadsByPriority,
      clients_by_status: clientsByStatus,
      report_text: reportText
    }
  }
];

const item = $input.first().json;

return [
  {
    json: {
      ...item
    },
    binary: {
      data: {
        data: Buffer.from(item.report_text, "utf8").toString("base64"),
        mimeType: "text/plain",
        fileName: item.report_file_name
      }
    }
  }
];

const metrics = $node["Procesar Métricas"].json;
const driveFile = $node["Guardar Reporte en Google Drive"].json;

return [
  {
    json: {
      success: true,
      message: "Reporte generado correctamente.",
      report_date: metrics.report_date,
      report_file_name: metrics.report_file_name,
      report_file_id: driveFile.id || "DRIVE_FILE_ID",
      report_url: driveFile.webViewLink || (driveFile.id ? `https://drive.google.com/file/d/${driveFile.id}/view` : "REPORT_URL_NOT_AVAILABLE"),
      total_leads: metrics.total_leads,
      total_clients: metrics.total_clients,
      leads_by_status: metrics.leads_by_status,
      leads_by_priority: metrics.leads_by_priority,
      clients_by_status: metrics.clients_by_status
    }
  }
];
